<div class="row g-2"><?php foreach(['Total cables'=>$stats['cables'],'En reparación'=>$stats['reparacion'],'Informes del día'=>$stats['informes_hoy'],'Stock bajo'=>$stats['stock_bajo']] as $k=>$v): ?><div class="col-md-3"><div class="kpi"><span><?= e($k) ?></span><strong><?= e((string)$v) ?></strong></div></div><?php endforeach; ?></div><div class="row g-2 mt-1"><div class="col-lg-6"><div class="card-dark"><h6>Últimas entregas</h6><table class="table table-dark table-sm datatable"><thead><tr><th>ID</th><th>Receptor</th><th>Fecha</th><th>Estado</th></tr></thead><tbody><?php foreach($stats['ult_entregas'] as $r): ?><tr><td><?= $r['id'] ?></td><td><?= e($r['receptor']) ?></td><td><?= e($r['fecha_entrega']) ?></td><td><?= badge($r['estado']) ?></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-lg-6"><div class="card-dark"><h6>Últimos informes</h6><table class="table table-dark table-sm datatable"><thead><tr><th>ID</th><th>Cable</th><th>Estado</th><th>Fecha</th></tr></thead><tbody><?php foreach($stats['ult_informes'] as $r): ?><tr><td><?= $r['id'] ?></td><td><?= e($r['numero_cable']) ?></td><td><?= badge($r['estado_informe']) ?></td><td><?= e($r['created_at']) ?></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-lg-6"><div class="card-dark"><canvas id="chartEstados" data-values='<?= json_encode($stats['cable_estados']) ?>'></canvas></div></div><div class="col-lg-6"><div class="card-dark"><canvas id="chartMateriales" data-values='<?= json_encode($stats['mat_usados']) ?>'></canvas></div></div></div>
